        self.board = [['' for _ in range(3)] for _ in range(3)]
        self.buttons = [[tk.Button(self.root, text="", height=5, width=10, command=lambda row=i, col=j: self.on_button_click(row, col)) for j in range(3)] for i in range(3)]

